#!/usr/bin/env python3
from pathlib import Path
import json

ROOT = Path.cwd()
FILES = {'.env.production.example': '# Betsy Home production environment template\n# Copy this into your deployment provider\'s Environment Variables panel.\n# Do not commit real secrets.\n\nNODE_ENV=production\n\n# App URL\nNEXTAUTH_URL=https://your-domain.com\nNEXT_PUBLIC_APP_URL=https://your-domain.com\n\n# Generate with:\n# openssl rand -base64 32\nNEXTAUTH_SECRET=replace-with-long-random-secret\n\n# Supabase / Prisma\n# Recommended: Supabase Transaction Pooler for production serverless deployments.\nDATABASE_URL="postgresql://postgres.PROJECT_REF:YOUR_PASSWORD@aws-1-us-east-1.pooler.supabase.com:6543/postgres?schema=public&pgbouncer=true&connection_limit=5&pool_timeout=60&sslmode=require"\n\n# Optional direct URL for Prisma migrations only, if you use one later.\n# DIRECT_URL="postgresql://postgres:YOUR_PASSWORD@db.PROJECT_REF.supabase.co:5432/postgres?sslmode=require"\n\n# Stripe test or live keys\n# Use test keys for staging, live keys only for production launch.\nSTRIPE_SECRET_KEY=sk_test_replace_me\nNEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY=pk_test_replace_me\nSTRIPE_WEBHOOK_SECRET=whsec_replace_me\n\n# Marketplace safety\nDEMO_SELLER_FALLBACKS_ENABLED=false\nDEMO_ACCOUNTS_ENABLED=false\n\n# Optional email provider later\n# RESEND_API_KEY=\n# SUPPORT_EMAIL=support@your-domain.com\n', 'docs/deployment-readiness-checklist.md': "# Betsy Home deployment readiness checklist\n\nUse this before deploying the MVP to staging or production.\n\n## 1. Environment variables\n\nRequired before production:\n\n- `DATABASE_URL`\n- `NEXTAUTH_URL`\n- `NEXTAUTH_SECRET`\n- `STRIPE_SECRET_KEY`\n- `NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY`\n- `STRIPE_WEBHOOK_SECRET`\n- `DEMO_SELLER_FALLBACKS_ENABLED=false`\n\nRecommended:\n\n- `NEXT_PUBLIC_APP_URL`\n- `DEMO_ACCOUNTS_ENABLED=false`\n\n## 2. Database\n\nUse Supabase transaction pooler for deployed/serverless apps:\n\n```text\nhost: aws-1-us-east-1.pooler.supabase.com\nport: 6543\nparams: pgbouncer=true&connection_limit=5&pool_timeout=60&sslmode=require\n```\n\nBefore deployment:\n\n- Confirm `/api/health` returns database OK.\n- Confirm `/admin/health` shows Database connection OK.\n- Avoid `npx prisma db pull` unless schema changed.\n- Run real schema migrations through Supabase SQL Editor or Prisma migration workflow, not random local introspection.\n\n## 3. Stripe\n\nFor staging:\n\n- Use Stripe test mode keys.\n- Configure Stripe webhook endpoint:\n  - `https://your-staging-domain.com/api/webhooks/stripe`\n- Add the webhook secret to `STRIPE_WEBHOOK_SECRET`.\n- Test:\n  - Checkout success\n  - Webhook payment confirmation\n  - Stripe Connect seller onboarding\n  - Refund follow-up flow\n\nFor production:\n\n- Replace test keys with live keys only after final testing.\n- Use a live webhook endpoint.\n- Confirm Connect account onboarding flow uses live mode.\n- Keep manual refund follow-up visible for admin.\n\n## 4. Auth and ownership\n\nBefore real users:\n\n- No hardcoded seller fallback should run in production.\n- Seller pages must only show shops/orders/products owned by the signed-in seller.\n- Admin-only pages must redirect non-admin users.\n- Customer pages must only show the signed-in customer's own orders.\n- Demo quick-login should be disabled or isolated from production.\n\n## 5. Smoke test after deployment\n\nRun these paths:\n\n```text\n/\n/login\n/search\n/product/...\n/cart\n/checkout/success\n/account/orders\n/seller/dashboard\n/seller/orders\n/seller/payments\n/seller/analytics\n/admin/dashboard\n/admin/activity\n/admin/payments\n/admin/refunds\n/admin/reports\n/admin/health\n/api/health\n/api/readiness\n```\n\n## 6. Launch blocker list\n\nDo not launch if any of these are true:\n\n- `/api/health` database check fails.\n- Seller fallback ownership is enabled.\n- Stripe webhook secret is missing.\n- Checkout creates unpaid or duplicate orders incorrectly.\n- Sellers can see other sellers' orders/products.\n- Customers can see other customers' orders.\n- Admin pages are accessible to seller/customer users.\n", 'src/lib/deployment-readiness.ts': 'type ReadinessStatus = "ok" | "warning" | "error";\n\ntype ReadinessItem = {\n  name: string;\n  status: ReadinessStatus;\n  message: string;\n  detail?: string;\n};\n\nfunction mask(value: string | undefined) {\n  if (!value) return "not configured";\n  if (value.length <= 8) return "configured";\n  return `${value.slice(0, 4)}…${value.slice(-4)}`;\n}\n\nfunction envItem(name: string, required = true): ReadinessItem {\n  const value = process.env[name];\n\n  if (value) {\n    return {\n      name,\n      status: "ok",\n      message: "Configured",\n      detail: mask(value),\n    };\n  }\n\n  return {\n    name,\n    status: required ? "error" : "warning",\n    message: required ? "Missing required environment variable" : "Not configured",\n  };\n}\n\nfunction parseDatabaseUrl() {\n  const raw = process.env.DATABASE_URL;\n  if (!raw) return null;\n\n  try {\n    return new URL(raw);\n  } catch {\n    return null;\n  }\n}\n\nfunction databaseItems(): ReadinessItem[] {\n  const url = parseDatabaseUrl();\n\n  if (!url) {\n    return [\n      {\n        name: "DATABASE_URL format",\n        status: "error",\n        message: "DATABASE_URL is missing or invalid",\n      },\n    ];\n  }\n\n  const items: ReadinessItem[] = [\n    {\n      name: "DATABASE_URL format",\n      status: "ok",\n      message: "DATABASE_URL parsed successfully",\n      detail: `${url.protocol}//${url.username}@${url.host}${url.pathname}`,\n    },\n  ];\n\n  const isPooler = url.host.includes("pooler.supabase.com");\n  const pgbouncer = url.searchParams.get("pgbouncer");\n  const sslmode = url.searchParams.get("sslmode");\n  const connectionLimit = Number(url.searchParams.get("connection_limit") ?? "0");\n  const poolTimeout = Number(url.searchParams.get("pool_timeout") ?? "0");\n\n  if (isPooler && pgbouncer !== "true") {\n    items.push({\n      name: "Supabase pooler pgbouncer",\n      status: "warning",\n      message: "Pooler URL should include pgbouncer=true",\n    });\n  } else if (isPooler) {\n    items.push({\n      name: "Supabase pooler pgbouncer",\n      status: "ok",\n      message: "Pooler URL includes pgbouncer=true",\n    });\n  }\n\n  if (sslmode !== "require") {\n    items.push({\n      name: "Database SSL",\n      status: "warning",\n      message: "DATABASE_URL should include sslmode=require",\n    });\n  } else {\n    items.push({\n      name: "Database SSL",\n      status: "ok",\n      message: "sslmode=require",\n    });\n  }\n\n  if (connectionLimit && connectionLimit < 3) {\n    items.push({\n      name: "Connection limit",\n      status: "warning",\n      message: "connection_limit is low for seller/admin dashboards",\n      detail: String(connectionLimit),\n    });\n  } else if (connectionLimit) {\n    items.push({\n      name: "Connection limit",\n      status: "ok",\n      message: "connection_limit is set",\n      detail: String(connectionLimit),\n    });\n  } else {\n    items.push({\n      name: "Connection limit",\n      status: "warning",\n      message: "connection_limit is not set",\n    });\n  }\n\n  if (poolTimeout && poolTimeout < 30) {\n    items.push({\n      name: "Pool timeout",\n      status: "warning",\n      message: "pool_timeout should be at least 30 seconds for local/Supabase stability",\n      detail: String(poolTimeout),\n    });\n  } else if (poolTimeout) {\n    items.push({\n      name: "Pool timeout",\n      status: "ok",\n      message: "pool_timeout is set",\n      detail: String(poolTimeout),\n    });\n  } else {\n    items.push({\n      name: "Pool timeout",\n      status: "warning",\n      message: "pool_timeout is not set",\n    });\n  }\n\n  return items;\n}\n\nfunction safetyItems(): ReadinessItem[] {\n  const demoSellerFallbacks = process.env.DEMO_SELLER_FALLBACKS_ENABLED;\n  const demoAccounts = process.env.DEMO_ACCOUNTS_ENABLED;\n  const isProduction = process.env.NODE_ENV === "production";\n\n  return [\n    {\n      name: "Demo seller fallbacks",\n      status:\n        demoSellerFallbacks === "false"\n          ? "ok"\n          : isProduction\n            ? "error"\n            : "warning",\n      message:\n        demoSellerFallbacks === "false"\n          ? "Disabled"\n          : "Set DEMO_SELLER_FALLBACKS_ENABLED=false before production",\n      detail: demoSellerFallbacks ?? "not configured",\n    },\n    {\n      name: "Demo accounts",\n      status:\n        demoAccounts === "false"\n          ? "ok"\n          : isProduction\n            ? "warning"\n            : "warning",\n      message:\n        demoAccounts === "false"\n          ? "Disabled"\n          : "Set DEMO_ACCOUNTS_ENABLED=false before public launch",\n      detail: demoAccounts ?? "not configured",\n    },\n  ];\n}\n\nfunction overall(items: ReadinessItem[]): ReadinessStatus {\n  if (items.some((item) => item.status === "error")) return "error";\n  if (items.some((item) => item.status === "warning")) return "warning";\n  return "ok";\n}\n\nexport function getDeploymentReadinessReport() {\n  const items: ReadinessItem[] = [\n    envItem("DATABASE_URL", true),\n    envItem("NEXTAUTH_URL", true),\n    envItem("NEXTAUTH_SECRET", true),\n    envItem("STRIPE_SECRET_KEY", true),\n    envItem("NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY", true),\n    envItem("STRIPE_WEBHOOK_SECRET", true),\n    envItem("NEXT_PUBLIC_APP_URL", false),\n    ...databaseItems(),\n    ...safetyItems(),\n  ];\n\n  return {\n    generatedAt: new Date().toISOString(),\n    environment: process.env.NODE_ENV ?? "development",\n    overallStatus: overall(items),\n    items,\n  };\n}\n', 'src/app/api/readiness/route.ts': 'import { NextResponse } from "next/server";\nimport { getDeploymentReadinessReport } from "@/lib/deployment-readiness";\n\nexport const dynamic = "force-dynamic";\n\nexport async function GET() {\n  const report = getDeploymentReadinessReport();\n\n  return NextResponse.json(report, {\n    status: report.overallStatus === "error" ? 503 : 200,\n    headers: {\n      "Cache-Control": "no-store",\n    },\n  });\n}\n', 'src/app/(admin)/admin/deployment/page.tsx': 'import Link from "next/link";\nimport { getDeploymentReadinessReport } from "@/lib/deployment-readiness";\n\nexport const dynamic = "force-dynamic";\n\nfunction statusClass(status: string) {\n  if (status === "ok") return "bg-green-100 text-green-800";\n  if (status === "warning") return "bg-yellow-100 text-yellow-900";\n  return "bg-red-100 text-red-700";\n}\n\nfunction StatusBadge({ status }: { status: string }) {\n  return (\n    <span\n      className={`rounded-full px-3 py-1 text-xs font-black uppercase tracking-wide ${statusClass(\n        status\n      )}`}\n    >\n      {status}\n    </span>\n  );\n}\n\nexport default function AdminDeploymentPage() {\n  const report = getDeploymentReadinessReport();\n\n  const errors = report.items.filter((item) => item.status === "error").length;\n  const warnings = report.items.filter((item) => item.status === "warning").length;\n  const ok = report.items.filter((item) => item.status === "ok").length;\n\n  return (\n    <main className="mx-auto max-w-6xl px-6 py-12">\n      <div className="flex flex-wrap items-start justify-between gap-4">\n        <div>\n          <p className="text-sm font-bold uppercase tracking-[0.35em] text-clay">\n            Admin\n          </p>\n          <h1 className="mt-4 text-4xl font-black text-charcoal">\n            Deployment readiness\n          </h1>\n          <p className="mt-2 max-w-3xl text-charcoal/70">\n            Pre-launch environment, Stripe, database, and safety checks for Betsy Home.\n          </p>\n        </div>\n\n        <StatusBadge status={report.overallStatus} />\n      </div>\n\n      <section className="mt-8 grid gap-4 md:grid-cols-4">\n        <div className="rounded-3xl border border-clay/20 bg-white p-6">\n          <p className="text-sm text-charcoal/60">Overall</p>\n          <p className="mt-3 text-3xl font-black">{report.overallStatus.toUpperCase()}</p>\n        </div>\n        <div className="rounded-3xl border border-clay/20 bg-white p-6">\n          <p className="text-sm text-charcoal/60">OK</p>\n          <p className="mt-3 text-3xl font-black text-green-700">{ok}</p>\n        </div>\n        <div className="rounded-3xl border border-clay/20 bg-white p-6">\n          <p className="text-sm text-charcoal/60">Warnings</p>\n          <p className="mt-3 text-3xl font-black text-yellow-700">{warnings}</p>\n        </div>\n        <div className="rounded-3xl border border-clay/20 bg-white p-6">\n          <p className="text-sm text-charcoal/60">Errors</p>\n          <p className="mt-3 text-3xl font-black text-red-700">{errors}</p>\n        </div>\n      </section>\n\n      <section className="mt-6 rounded-3xl border border-clay/20 bg-white p-6">\n        <div className="flex flex-wrap items-center justify-between gap-3">\n          <h2 className="text-2xl font-black text-charcoal">Checks</h2>\n          <Link\n            href="/admin/health"\n            className="rounded-full border border-clay px-5 py-2 text-sm font-black text-clay"\n          >\n            Open health page\n          </Link>\n        </div>\n\n        <div className="mt-5 space-y-3">\n          {report.items.map((item) => (\n            <div\n              key={item.name}\n              className="rounded-2xl border border-clay/10 bg-cream p-4"\n            >\n              <div className="flex flex-wrap items-center justify-between gap-3">\n                <p className="font-black text-charcoal">{item.name}</p>\n                <StatusBadge status={item.status} />\n              </div>\n              <p className="mt-2 text-sm text-charcoal/70">{item.message}</p>\n              {item.detail ? (\n                <p className="mt-2 break-all rounded-xl bg-white p-3 text-xs text-charcoal/70">\n                  {item.detail}\n                </p>\n              ) : null}\n            </div>\n          ))}\n        </div>\n      </section>\n\n      <section className="mt-6 rounded-3xl border border-clay/20 bg-cream p-6">\n        <h2 className="text-xl font-black text-charcoal">Production rule</h2>\n        <p className="mt-2 text-charcoal/70">\n          Do not publicly launch until this page has no errors, Stripe webhooks are configured,\n          and demo seller fallbacks are disabled.\n        </p>\n      </section>\n    </main>\n  );\n}\n', 'scripts/check-production-readiness.cjs': 'function mask(value) {\n  if (!value) return "not configured";\n  if (value.length <= 8) return "configured";\n  return `${value.slice(0, 4)}…${value.slice(-4)}`;\n}\n\nfunction checkEnv(name, required = true) {\n  const value = process.env[name];\n  return {\n    name,\n    status: value ? "ok" : required ? "error" : "warning",\n    message: value ? "Configured" : required ? "Missing required env var" : "Not configured",\n    detail: mask(value),\n  };\n}\n\nfunction parseDatabaseUrl() {\n  if (!process.env.DATABASE_URL) return null;\n  try {\n    return new URL(process.env.DATABASE_URL);\n  } catch {\n    return null;\n  }\n}\n\nconst checks = [\n  checkEnv("DATABASE_URL", true),\n  checkEnv("NEXTAUTH_URL", true),\n  checkEnv("NEXTAUTH_SECRET", true),\n  checkEnv("STRIPE_SECRET_KEY", true),\n  checkEnv("NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY", true),\n  checkEnv("STRIPE_WEBHOOK_SECRET", true),\n  checkEnv("NEXT_PUBLIC_APP_URL", false),\n];\n\nconst url = parseDatabaseUrl();\nif (url) {\n  checks.push({\n    name: "DATABASE_URL host",\n    status: "ok",\n    message: `${url.username}@${url.host}${url.pathname}`,\n  });\n\n  checks.push({\n    name: "pgbouncer",\n    status: url.searchParams.get("pgbouncer") === "true" ? "ok" : "warning",\n    message: url.searchParams.get("pgbouncer") === "true"\n      ? "pgbouncer=true"\n      : "Pooler URLs should include pgbouncer=true",\n  });\n\n  checks.push({\n    name: "sslmode",\n    status: url.searchParams.get("sslmode") === "require" ? "ok" : "warning",\n    message: url.searchParams.get("sslmode") === "require"\n      ? "sslmode=require"\n      : "DATABASE_URL should include sslmode=require",\n  });\n} else {\n  checks.push({\n    name: "DATABASE_URL parse",\n    status: "error",\n    message: "DATABASE_URL missing or invalid",\n  });\n}\n\nchecks.push({\n  name: "Demo seller fallbacks",\n  status: process.env.DEMO_SELLER_FALLBACKS_ENABLED === "false" ? "ok" : "warning",\n  message: "Set DEMO_SELLER_FALLBACKS_ENABLED=false before production",\n  detail: process.env.DEMO_SELLER_FALLBACKS_ENABLED ?? "not configured",\n});\n\nconst errors = checks.filter((check) => check.status === "error").length;\nconst warnings = checks.filter((check) => check.status === "warning").length;\n\nconsole.log("Betsy Home production readiness");\nconsole.log("--------------------------------");\nfor (const check of checks) {\n  console.log(`[${check.status.toUpperCase()}] ${check.name}: ${check.message}`);\n  if (check.detail) console.log(`  ${check.detail}`);\n}\n\nconsole.log("--------------------------------");\nconsole.log(`Errors: ${errors}`);\nconsole.log(`Warnings: ${warnings}`);\n\nif (errors) {\n  process.exitCode = 1;\n}\n'}

def ensure_parent(path: Path):
    path.parent.mkdir(parents=True, exist_ok=True)

def write_file(path_str: str, content: str):
    path = ROOT / path_str
    ensure_parent(path)
    path.write_text(content, encoding="utf-8")
    print(f"wrote {path_str}")

for path_str, content in FILES.items():
    write_file(path_str, content)

pkg_path = ROOT / "package.json"
if pkg_path.exists():
    try:
        pkg = json.loads(pkg_path.read_text(encoding="utf-8"))
        scripts = pkg.setdefault("scripts", {})
        scripts.setdefault("readiness", "node scripts/check-production-readiness.cjs")
        pkg_path.write_text(json.dumps(pkg, indent=2) + "\n", encoding="utf-8")
        print("updated package.json with readiness script")
    except Exception as error:
        print("package.json update skipped:", error)

print("\nDone.")
print("Next:")
print("  rm -rf .next")
print("  npx prisma generate")
print("  npm run dev")
print("Then open:")
print("  http://localhost:3000/admin/deployment")
print("  http://localhost:3000/api/readiness")
